impl Solution { pub fn min_days(bloom_day: Vec<i32>, m: i32, k: i32) -> i32 { if (m as i64 * k as i64) > bloom_day.len() as i64 { return -1; } let (mut l, mut r) = (1, 1_000_000_000); while l < r { let mid = l + (r - l) / 2; let (mut bouquets, mut flowers) = (0, 0); for &d in &bloom_day { if d <= mid { flowers += 1; if flowers == k { bouquets += 1; flowers = 0; } } else { flowers = 0; } } if bouquets >= m { r = mid; } else { l = mid + 1; } } l } }